// ===== Fade-up animation on scroll =====
const observer = new IntersectionObserver((entries) => {
  entries.forEach(entry => {
    if (entry.isIntersecting) {
      entry.target.classList.add('visible');
    }
  });
}, { threshold: 0.1 });

document.querySelectorAll('.fade-up').forEach(el => observer.observe(el));

// ===== 공지사항 / 가정통신문 =====
let notices = [
  {
    id: 1,
    title: '3월 현장학습 안내',
    content: '안녕하세요, 해오름 아동센터입니다.\n\n3월 28일(금) 봄맞이 현장학습을 진행합니다.\n\n장소: OO공원\n시간: 오전 10시 ~ 오후 2시\n준비물: 도시락, 물, 돗자리\n\n참가 동의서를 3월 25일까지 제출해 주세요.\n\n감사합니다.',
    category: '통신문',
    date: '2026.03.22',
    file: '현장학습_동의서.pdf'
  },
  {
