}

.time-dot.snack { background: var(--warning); }
.time-dot.meal { background: var(--success); }
.time-dot.special { background: #ab7ae0; }
.time-dot.rest { background: var(--text-light); }

.time-name {
  font-size: 0.95rem;
  font-weight: 600;
  letter-spacing: -0.01em;
}

/* ===== MEAL / 식단표 ===== */
.meal-week-nav {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 24px;
  margin-bottom: 24px;
}

.meal-grid {
  display: grid;
  grid-template-columns: repeat(5, 1fr);
  gap: 12px;
}

.meal-card {
  background: var(--card);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 20px 16px;
  text-align: center;
  transition: all var(--transition);
}

.meal-card:hover {
  transform: translateY(-4px);
  box-shadow: var(--shadow-lg);
  border-color: transparent;
}

.meal-card.today {
  border-color: var(--primary);
  background: var(--primary-light);
}

.meal-day {
  font-size: 0.8rem;
  font-weight: 700;
  color: var(--text-sub);
  margin-bottom: 4px;
}

.meal-date {
  font-size: 1.1rem;
  font-weight: 800;
  margin-bottom: 16px;
  letter-spacing: -0.02em;
}

.meal-type {
  font-size: 0.75rem;
  font-weight: 700;
  color: var(--primary);
  margin-bottom: 6px;
  margin-top: 12px;
}

.meal-menu {
  font-size: 0.85rem;
  color: var(--text-sub);
  line-height: 1.6;
}

/* ===== ATTENDANCE / 출석 ===== */
.attendance-summary {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 12px;
  margin-bottom: 24px;
}

.att-summary-card {
  background: var(--card);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 24px;
  text-align: center;
}

.att-summary-number {
  font-size: 2rem;
  font-weight: 900;
  letter-spacing: -0.03em;
}

.att-summary-number.present { color: var(--success); }
.att-summary-number.absent { color: var(--danger); }
.att-summary-number.late { color: var(--warning); }

.att-summary-label {
  font-size: 0.85rem;
  color: var(--text-sub);
  margin-top: 4px;
  font-weight: 600;
}

.attendance-list {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));
  gap: 8px;
}

.att-item {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 12px 16px;
  background: var(--card);
  border: 1px solid var(--border);
  border-radius: var(--radius-sm);
  transition: all var(--transition);
}

.att-item:hover {
  border-color: var(--primary);
}

.att-avatar {
  width: 36px;
  height: 36px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 0.85rem;
  font-weight: 700;
  color: #fff;
  flex-shrink: 0;
}

.att-avatar.present { background: var(--success); }
.att-avatar.absent { background: var(--danger); }
.att-avatar.late { background: var(--warning); }

.att-name {
  font-size: 0.9rem;
  font-weight: 600;
  letter-spacing: -0.01em;
}

.att-status {
  font-size: 0.75rem;
  color: var(--text-sub);
}

/* ===== GALLERY ===== */
.gallery-grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 16px;
}

.gallery-card {
  border-radius: var(--radius);
  overflow: hidden;
  background: var(--card);
  border: 1px solid var(--border);
  transition: all var(--transition);
  cursor: pointer;
}

.gallery-card:hover {
  transform: translateY(-4px);
  box-shadow: var(--shadow-lg);
  border-color: transparent;
}

.gallery-img {
  height: 180px;
  display: flex;
  align-items: center;
  justify-content: center;
}

.gallery-img span {
  color: rgba(255, 255, 255, 0.9);
  font-size: 1.1rem;
  font-weight: 800;
  letter-spacing: -0.02em;
}

.gallery-info {
  padding: 16px 20px;
}

.gallery-title {
  font-size: 1rem;
  font-weight: 700;
  margin-bottom: 4px;
  letter-spacing: -0.02em;
}

.gallery-date {
  font-size: 0.8rem;
  color: var(--text-sub);
}

/* ===== CONTACT ===== */
.contact-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 12px;
}

.contact-card {
  background: var(--card);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 28px 20px;
  text-align: center;
  transition: all var(--transition);
}

.contact-card:hover {
  transform: translateY(-4px);
  box-shadow: var(--shadow-lg);
  border-color: transparent;
}

.contact-icon {
  font-size: 2rem;
  margin-bottom: 12px;
}

.contact-title {
  font-size: 0.9rem;
  font-weight: 700;
  margin-bottom: 4px;
  letter-spacing: -0.02em;
}

.contact-info {
  font-size: 0.85rem;
  color: var(--primary);
  font-weight: 600;
}

/* ===== FOOTER ===== */
footer {
  text-align: center;
  padding: 60px 24px;
  background: var(--bg-sub);
  margin-top: 40px;
}

.footer-logo {
  font-size: 1.1rem;
  font-weight: 800;
  margin-bottom: 12px;
}

.footer-logo span {
  color: var(--primary);
  margin-left: 2px;
}

.footer-text {
  font-size: 0.8rem;
  color: var(--text-sub);
  margin-top: 4px;
}

/* ===== ANIMATION ===== */
.fade-up {
  opacity: 0;
  transform: translateY(30px);
  transition: opacity 0.7s ease, transform 0.7s ease;
}

.fade-up.visible {
  opacity: 1;
  transform: translateY(0);
}

/* ===== MODAL ===== */
.modal-overlay {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: rgba(0, 0, 0, 0.4);
  backdrop-filter: blur(4px);
  z-index: 2000;
  display: flex;
  align-items: center;
  justify-content: center;
  opacity: 0;
  pointer-events: none;
  transition: opacity var(--transition);
}

.modal-overlay.active {
  opacity: 1;
  pointer-events: auto;
}

.modal {
  background: var(--card);
  border-radius: var(--radius);
  padding: 36px;
  max-width: 560px;
  width: 90%;
  max-height: 80vh;
  overflow-y: auto;
  transform: translateY(20px);
  transition: transform var(--transition);
}

.modal-overlay.active .modal {
  transform: translateY(0);
}

.modal-title {
  font-size: 1.3rem;
  font-weight: 800;
  margin-bottom: 8px;
  letter-spacing: -0.03em;
}

.modal-meta {
  display: flex;
  align-items: center;
  gap: 8px;
  margin-bottom: 20px;
}

.modal-body {
  font-size: 0.95rem;
  line-height: 1.8;
  color: var(--text);
  white-space: pre-wrap;
}

.modal-close {
  margin-top: 24px;
  width: 100%;
  padding: 14px;
  border: none;
  border-radius: var(--radius-sm);
  background: var(--bg-sub);
  color: var(--text);
  font-size: 0.95rem;
  font-weight: 700;
  cursor: pointer;
  transition: all var(--transition);
}

.modal-close:hover {
  background: var(--border);
}

/* ===== RESPONSIVE ===== */
@media (max-width: 768px) {
  nav {
    padding: 0 20px;
  }

  .nav-links {
    display: none;
  }

  .stats {
    grid-template-columns: repeat(2, 1fr);
    margin-top: -20px;
  }

  .meal-grid {
    grid-template-columns: repeat(2, 1fr);
  }

  .gallery-grid {
    grid-template-columns: 1fr;
  }

  .contact-grid {
    grid-template-columns: repeat(2, 1fr);
  }
}

@media (max-width: 480px) {
  .meal-grid {
    grid-template-columns: 1fr;
  }

  .contact-grid {
    grid-template-columns: 1fr;
  }

  .hero-buttons {
    flex-direction: column;
    width: 100%;
    padding: 0 20px;
  }

  .btn-primary,
  .btn-secondary {
    text-align: center;
  }
}

