@import url('https://fonts.googleapis.com/css2?family=Pretendard:wght@400;600;700;800;900&display=swap');

/* ===== RESET & BASE ===== */
*, *::before, *::after {
  margin: 0;
  padding: 0;
  box-sizing: border-box;
}

:root {
  --bg: #fffcfa;
  --bg-sub: #faf5f0;
  --text: #2d2319;
  --text-sub: #8c7e72;
  --text-light: #bfb3a8;
  --primary: #ff7854;
  --primary-light: #fff0eb;
  --primary-dark: #e85d3a;
  --danger: #ef5350;
  --danger-light: #fce4ec;
  --success: #66bb6a;
  --success-light: #e8f5e9;
  --warning: #ffa726;
  --warning-light: #fff8e1;
  --border: #ede6df;
  --card: #ffffff;
  --shadow: 0 2px 8px rgba(45, 35, 25, 0.05);
  --shadow-lg: 0 8px 30px rgba(45, 35, 25, 0.1);
  --radius: 16px;
  --radius-sm: 10px;
  --radius-xs: 6px;
  --font: 'Pretendard', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  --transition: 0.3s cubic-bezier(0.4, 0, 0.2, 1);
}

html {
  scroll-behavior: smooth;
  font-size: 16px;
}

body {
  font-family: var(--font);
  background: var(--bg);
  color: var(--text);
  line-height: 1.6;
  -webkit-font-smoothing: antialiased;
  overflow-x: hidden;
}

a {
  text-decoration: none;
  color: inherit;
}

ul {
  list-style: none;
}

/* ===== NAV ===== */
nav {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  z-index: 1000;
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0 40px;
  height: 64px;
  background: rgba(255, 252, 250, 0.88);
  backdrop-filter: blur(20px);
  -webkit-backdrop-filter: blur(20px);
  border-bottom: 1px solid var(--border);
}

.nav-logo {
  font-size: 1.1rem;
  font-weight: 800;
  color: var(--text);
  letter-spacing: -0.02em;
}

.nav-logo span {
  color: var(--primary);
  margin-left: 2px;
}

.nav-links {
  display: flex;
  gap: 32px;
}

.nav-links a {
  font-size: 0.9rem;
  font-weight: 600;
  color: var(--text-sub);
  transition: color var(--transition);
  letter-spacing: -0.01em;
}

.nav-links a:hover {
  color: var(--text);
}

.nav-cta {
  padding: 8px 20px;
  border: none;
  border-radius: 20px;
  background: var(--primary);
  color: #fff;
  font-size: 0.85rem;
  font-weight: 700;
  cursor: pointer;
  transition: all var(--transition);
  letter-spacing: -0.01em;
}

.nav-cta:hover {
  background: var(--primary-dark);
  transform: translateY(-1px);
}

/* ===== HERO ===== */
.hero {
  min-height: 100vh;
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
  text-align: center;
  padding: 120px 24px 80px;
}

.hero-badge {
  display: inline-block;
  padding: 6px 16px;
  border-radius: 20px;
  background: var(--primary-light);
  color: var(--primary);
