  font-weight: 700;
  margin-bottom: 24px;
  letter-spacing: -0.01em;
}

.hero h1 {
  font-size: clamp(2.5rem, 6vw, 4.5rem);
  font-weight: 900;
  line-height: 1.15;
  letter-spacing: -0.04em;
  color: var(--text);
  margin-bottom: 20px;
}

.hero .highlight {
  color: var(--primary);
}

.hero p {
