  margin-bottom: 36px;
  line-height: 1.7;
  letter-spacing: -0.01em;
}

.hero-buttons {
  display: flex;
  gap: 12px;
}

.btn-primary {
  padding: 14px 32px;
  border-radius: 12px;
  background: var(--primary);
  color: #fff;
  font-size: 1rem;
  font-weight: 700;
  transition: all var(--transition);
  letter-spacing: -0.01em;
}

.btn-primary:hover {
  background: var(--primary-dark);
  transform: translateY(-2px);
