  font-weight: 700;
  cursor: pointer;
  transition: all var(--transition);
  margin-top: 8px;
  letter-spacing: -0.01em;
}

.btn-upload:hover {
  background: var(--primary-dark);
  transform: translateY(-1px);
}

/* 공지 리스트 */
.notice-list {
  display: flex;
  flex-direction: column;
  gap: 12px;
}

.notice-card {
  background: var(--card);
