  padding: 6px 12px;
  background: var(--bg-sub);
  border-radius: var(--radius-xs);
  font-size: 0.8rem;
  color: var(--text-sub);
  font-weight: 600;
}

/* ===== CALENDAR / 시간표 ===== */
.month-nav {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 24px;
  margin-bottom: 24px;
}

.month-btn {
  width: 40px;
  height: 40px;
  border: 1px solid var(--border);
  border-radius: 50%;
  background: var(--card);
  font-size: 1rem;
  color: var(--text);
  cursor: pointer;
  transition: all var(--transition);
  display: flex;
  align-items: center;
  justify-content: center;
  font-weight: 600;
}

.month-btn:hover {
  background: var(--bg-sub);
  border-color: var(--primary);
  color: var(--primary);
}

.month-label {
  font-size: 1.2rem;
  font-weight: 800;
  letter-spacing: -0.02em;
  min-width: 140px;
  text-align: center;
}

.calendar {
  display: grid;
  grid-template-columns: repeat(7, 1fr);
  gap: 4px;
  margin-bottom: 32px;
}

.cal-header {
  text-align: center;
  font-size: 0.8rem;
  font-weight: 700;
  color: var(--text-sub);
  padding: 8px 0;
}

.cal-header:first-child {
