}

.cal-event-tag {
  font-size: 0.55rem;
  font-weight: 700;
  padding: 1px 3px;
  border-radius: 3px;
  background: var(--primary-light);
  color: var(--primary);
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
  line-height: 1.3;
  text-align: center;
}

.cal-event-tag.holiday {
