  height: 28px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
}

.cal-day.selected {
  background: var(--primary-light);
}

.cal-day.other-month {
  color: var(--text-light);
}

.cal-day.other-month .cal-event-tag {
  display: none;
}

.cal-day.sunday, .cal-day.sunday .cal-num {
  color: var(--danger);
}

.cal-day.saturday, .cal-day.saturday .cal-num {
  color: #5c9eff;
}

.cal-day.today .cal-num {
  color: #fff;
}

/* 일별 시간표 */
.day-schedule {
  background: var(--bg-sub);
  border-radius: var(--radius);
  padding: 28px;
}

.day-title {
  font-size: 1.1rem;
  font-weight: 800;
  margin-bottom: 20px;
  letter-spacing: -0.02em;
}

.timetable {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.time-slot {
  display: flex;
  align-items: center;
  gap: 16px;
  padding: 14px 16px;
  background: var(--card);
  border-radius: var(--radius-sm);
  transition: all var(--transition);
}

.time-slot:hover {
  transform: translateX(4px);
}

.time-text {
  font-size: 0.85rem;
  font-weight: 700;
  color: var(--text-sub);
  min-width: 110px;
  letter-spacing: -0.01em;
}

.time-dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background: var(--primary);
  flex-shrink: 0;
}

.time-dot.snack { background: var(--warning); }
.time-dot.meal { background: var(--success); }
.time-dot.special { background: #ab7ae0; }
.time-dot.rest { background: var(--text-light); }

.time-name {
