  font-weight: 600;
  letter-spacing: -0.01em;
}

/* ===== MEAL / 식단표 ===== */
.meal-week-nav {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 24px;
  margin-bottom: 24px;
}

.meal-grid {
