    title,
    content,
    category,
    date: dateStr,
    file: fileName
  });

  document.getElementById('noticeTitle').value = '';
  document.getElementById('noticeContent').value = '';
  document.getElementById('fileName').textContent = '';
  fileInput.value = '';

  renderNotices();
